import{_ as e,o as i,c as s,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Operaciones y seguridad","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/kafka/07-operaciones-y-seguridad.md","filePath":"data-engineering/kafka/07-operaciones-y-seguridad.md","lastUpdated":1782521464000}'),o={name:"data-engineering/kafka/07-operaciones-y-seguridad.md"};function t(r,a,c,l,p,d){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="operaciones-y-seguridad" tabindex="-1">Operaciones y seguridad <a class="header-anchor" href="#operaciones-y-seguridad" aria-label="Permalink to &quot;Operaciones y seguridad&quot;">​</a></h1><p>Kafka es infraestructura critica cuando conecta servicios y datos. Operarlo bien exige seguridad, observabilidad, backups de configuracion y disciplina de cambios.</p><h2 id="seguridad-en-capas" tabindex="-1">Seguridad en capas <a class="header-anchor" href="#seguridad-en-capas" aria-label="Permalink to &quot;Seguridad en capas&quot;">​</a></h2><p>Capas habituales:</p><ul><li>Red privada.</li><li>TLS.</li><li>Autenticacion.</li><li>Autorizacion.</li><li>Auditoria.</li><li>Gestion de secretos.</li></ul><h2 id="tls" tabindex="-1">TLS <a class="header-anchor" href="#tls" aria-label="Permalink to &quot;TLS&quot;">​</a></h2><p>TLS cifra comunicacion entre clientes y brokers.</p><p>Sin TLS, eventos y credenciales pueden viajar en claro dentro de la red.</p><h2 id="autenticacion" tabindex="-1">Autenticacion <a class="header-anchor" href="#autenticacion" aria-label="Permalink to &quot;Autenticacion&quot;">​</a></h2><p>Mecanismos comunes:</p><ul><li>SASL/SCRAM.</li><li>mTLS.</li><li>OAuth/OIDC en plataformas compatibles.</li></ul><p>Ejemplo conceptual:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sasl.mechanism=SCRAM-SHA-512</span></span>
<span class="line"><span>security.protocol=SASL_SSL</span></span></code></pre></div><h2 id="acls" tabindex="-1">ACLs <a class="header-anchor" href="#acls" aria-label="Permalink to &quot;ACLs&quot;">​</a></h2><p>Las ACLs controlan quien puede leer, escribir o administrar recursos.</p><p>Ejemplo conceptual:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User:billing-service puede READ orders.created</span></span>
<span class="line"><span>User:orders-service puede WRITE orders.created</span></span></code></pre></div><p>Principio: minimo privilegio.</p><h2 id="configuracion-de-topics" tabindex="-1">Configuracion de topics <a class="header-anchor" href="#configuracion-de-topics" aria-label="Permalink to &quot;Configuracion de topics&quot;">​</a></h2><p>Parametros importantes:</p><ul><li><code>retention.ms</code></li><li><code>retention.bytes</code></li><li><code>cleanup.policy</code></li><li><code>min.insync.replicas</code></li><li><code>replication.factor</code></li><li><code>partitions</code></li></ul><h2 id="min-insync-replicas" tabindex="-1">min.insync.replicas <a class="header-anchor" href="#min-insync-replicas" aria-label="Permalink to &quot;min.insync.replicas&quot;">​</a></h2><p>Con <code>acks=all</code>, este valor define cuantas replicas sincronizadas deben confirmar.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>replication.factor=3</span></span>
<span class="line"><span>min.insync.replicas=2</span></span>
<span class="line"><span>acks=all</span></span></code></pre></div><p>Permite tolerar la perdida de un broker sin aceptar escrituras inseguras.</p><h2 id="retencion" tabindex="-1">Retencion <a class="header-anchor" href="#retencion" aria-label="Permalink to &quot;Retencion&quot;">​</a></h2><p>Kafka borra eventos segun tiempo o tamano:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>retention.ms=604800000</span></span>
<span class="line"><span>retention.bytes=10737418240</span></span></code></pre></div><p>La retencion debe cubrir el tiempo maximo de reprocesamiento esperado.</p><h2 id="log-compaction" tabindex="-1">Log compaction <a class="header-anchor" href="#log-compaction" aria-label="Permalink to &quot;Log compaction&quot;">​</a></h2><p><code>cleanup.policy=compact</code> conserva el ultimo valor por key.</p><p>Util para:</p><ul><li>Estados actuales.</li><li>CDC.</li><li>Tablas compactadas.</li></ul><p>No es igual que retencion historica completa.</p><h2 id="operaciones-de-riesgo" tabindex="-1">Operaciones de riesgo <a class="header-anchor" href="#operaciones-de-riesgo" aria-label="Permalink to &quot;Operaciones de riesgo&quot;">​</a></h2><ul><li>Reducir retencion sin revisar consumidores.</li><li>Borrar topics manualmente.</li><li>Cambiar partitions sin analizar orden.</li><li>Desactivar ACLs temporalmente.</li><li>Hacer rolling restart sin health checks.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Gestiona topics como codigo cuando sea posible.</li><li>Revisa ACLs en pull request.</li><li>Usa TLS y autenticacion en entornos compartidos.</li><li>Define owners para topics.</li><li>Monitoriza lag, ISR, under-replicated partitions y errores.</li><li>Documenta runbooks de incidentes.</li></ul>`,39)])])}const m=e(o,[["render",t]]);export{h as __pageData,m as default};
